mapper.select:
SELECT place_id
FROM FAVORITE
WHERE user_id = #{user_id}

SELECT p.PLACE_ID , COUNT(rv.REVIEW_ID) AS REVIEW_COUNT , NVL(ROUND(AVG(rv.RATING),1),0) AS AVG_RATING FROM PLACE p LEFT JOIN REVIEW rv ON p.PLACE_ID = rv.PLACE_ID AND rv.STATUS = 'DISPLAY' WHERE p.PLACE_ID IN
#{id}
GROUP BY p.PLACE_ID
